// ===================================================
// WF-17 Step 1: NocoDB Webhook 파싱
// tbl_Classes status → active 변경 감지 시 메이크샵 상품 자동 등록
// NocoDB After Update 이벤트 구조:
// { type: 'records.after.update', data: { rows: [...], previous_rows: [...] } }
// ===================================================

const input = $input.first().json;
const body = input.body || input;

let record = {};
let prevRecord = {};

if (body.data && body.data.rows && body.data.rows.length > 0) {
  record = body.data.rows[0];
  prevRecord = (body.data.previous_rows && body.data.previous_rows[0]) ? body.data.previous_rows[0] : {};
} else if (body.rows && body.rows.length > 0) {
  record = body.rows[0];
} else {
  record = body;
}

const currentStatus = String(record.status || '').toLowerCase().trim();

// active 변경이 아니면 스킵
if (currentStatus !== 'active') {
  return [{ json: { _skip: true, _skipReason: 'status가 active가 아님: ' + currentStatus, _timestamp: new Date().toISOString() } }];
}

// 이미 메이크샵 상품이 등록된 경우 스킵 (중복 방지)
const existingProductId = String(record.makeshop_product_id || '').trim();
if (existingProductId && existingProductId !== '0' && existingProductId !== '') {
  return [{ json: { _skip: true, _skipReason: '이미 메이크샵 상품 등록됨: ' + existingProductId, _timestamp: new Date().toISOString() } }];
}

// 필수 필드 추출
const nocodbRowId = String(record.Id || record.id || '').trim();
const classId = String(record.class_id || '').trim();
const title = String(record.title || record.class_name || '').trim();
const price = parseInt(record.price || 0, 10);
const partnerCode = String(record.partner_code || '').trim();
const maxStudents = parseInt(record.max_students || 10, 10);
const description = String(record.description || title + ' 강의 안내').trim().substring(0, 1000);
const location = String(record.location || '').trim();
const imageUrl = String(record.image_url || '').trim();

if (!nocodbRowId || !title || !price) {
  return [{ json: { _skip: true, _skipReason: 'Id, title, price 중 누락: ' + JSON.stringify({ nocodbRowId, title, price }), _timestamp: new Date().toISOString() } }];
}

if (!partnerCode) {
  return [{ json: { _skip: true, _skipReason: 'partner_code 누락 — 파트너 승인 후 강의를 등록해야 합니다', _timestamp: new Date().toISOString() } }];
}

return [{ json: {
  _skip: false,
  _nocodbRowId: nocodbRowId,
  _classId: classId,
  _title: title,
  _price: price,
  _partnerCode: partnerCode,
  _maxStudents: maxStudents,
  _description: description,
  _location: location,
  _imageUrl: imageUrl,
  _timestamp: new Date().toISOString()
} }];

// ===================================================
// WF-17 Step 3: 파트너 이메일/이름 추출
// ===================================================

const partnerResp = $input.first().json;
const classData = $('Parse NocoDB Webhook').first().json;

let partnerEmail = '';
let partnerName = '';
let partnerStudioName = '';

try {
  const partners = partnerResp.list || partnerResp.data || (partnerResp.datas ? partnerResp.datas : []);
  const partner = Array.isArray(partners) && partners.length > 0 ? partners[0] : {};
  partnerEmail = String(partner.email || '').trim();
  partnerName = String(partner.name || partner.partner_name || '').trim();
  partnerStudioName = String(partner.studio_name || '').trim();
} catch (e) {
  // 파트너 정보 없어도 강의 상품 등록은 진행
}

return [{ json: {
  ...classData,
  _partnerEmail: partnerEmail,
  _partnerName: partnerName,
  _partnerStudioName: partnerStudioName
} }];

// ===================================================
// WF-17 Step 5: 메이크샵 상품 등록 응답 처리
// 응답에서 branduid 직접 추출 시도
// 없으면 이후 검색 단계에서 찾음
// ===================================================

const apiResp = $input.first().json;
const classData = $('Process Partner Data').first().json;

let directBranduid = '';
let regSuccess = false;
let regError = '';

try {
  if (apiResp.return_code === '0000') {
    regSuccess = true;
    if (apiResp.datas && apiResp.datas[0]) {
      directBranduid = String(apiResp.datas[0].branduid || '').trim();
    }
    // 일부 메이크샵 API는 최상위에 branduid 반환
    if (!directBranduid && apiResp.branduid) {
      directBranduid = String(apiResp.branduid).trim();
    }
  } else {
    regError = 'return_code=' + (apiResp.return_code || 'unknown') + ' | ' + JSON.stringify(apiResp).substring(0, 300);
    // 등록 실패해도 검색 시도 (이미 동명 상품이 있을 수 있음)
  }
} catch (e) {
  regError = '파싱 오류: ' + e.message;
}

return [{ json: {
  ...classData,
  _directBranduid: directBranduid,
  _regSuccess: regSuccess,
  _regError: regError
} }];

// ===================================================
// WF-17 Step 7: 메이크샵 상품 검색 결과에서 branduid 추출
// 1순위: 등록 응답에서 직접 받은 branduid
// 2순위: 동일 이름+가격 상품 검색
// ===================================================

const searchResp = $input.first().json;
const prevData = $('Process Registration').first().json;

let branduid = prevData._directBranduid || '';
let brandcode = '';
let xcode = '022';
let mcode = '000';
let productFound = !!branduid;

// 직접 받은 branduid가 없으면 검색 결과에서 찾기
if (!productFound) {
  try {
    // 메이크샵 상품 목록 API 응답 구조: { return_code, count, datas: [...] }
    const datas = searchResp.datas || searchResp.data || (Array.isArray(searchResp) ? searchResp : []);
    if (Array.isArray(datas) && datas.length > 0) {
      // 같은 이름과 가격인 상품 찾기 (정확 일치 우선)
      let match = datas.find(p =>
        String(p.product_name || '').trim() === prevData._title &&
        parseInt(p.sellprice || 0, 10) === prevData._price
      );
      // 가격 무관하게 이름만 일치 시 첫 번째 사용
      if (!match) {
        match = datas.find(p => String(p.product_name || '').trim() === prevData._title);
      }
      if (match) {
        branduid = String(match.branduid || '').trim();
        brandcode = String(match.brandcode || '').trim();
        xcode = String(match.xcode || '022').trim();
        mcode = String(match.mcode || '000').trim();
        productFound = !!branduid;
      }
    }
  } catch (e) {
    // 검색 파싱 실패 → branduid 없이 계속
  }
}

// 메이크샵 brandcode 형식: xcode(3자리) + mcode(3자리) + 나머지
// 없으면 기본값으로 구성 (추후 수동 수정 가능)
if (!brandcode && branduid) {
  brandcode = xcode.padStart(3, '0') + mcode.padStart(3, '0') + '000251';
}

return [{ json: {
  ...prevData,
  _branduid: branduid,
  _brandcode: brandcode,
  _xcode: xcode,
  _mcode: mcode,
  _productFound: productFound,
  _searchError: !productFound ? '메이크샵 상품 검색에서 branduid를 찾지 못했습니다' : ''
} }];

// ===================================================
// WF-17 Step 9: 파트너 강의 오픈 안내 이메일 HTML 생성
// ===================================================

const data = $('Extract Branduid').first().json;

function escapeHtml(str) {
  if (!str) return '';
  return String(str)
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#39;');
}

const partnerName = escapeHtml(data._partnerName) || escapeHtml(data._partnerCode);
const classTitle = escapeHtml(data._title);
const classPrice = data._price ? data._price.toLocaleString('ko-KR') + '원' : '';
const branduid = data._branduid || '';
const classUrl = branduid ? 'https://foreverlove.co.kr/shop/shopdetail.html?branduid=' + branduid : 'https://foreverlove.co.kr/shop/page.html?id=2606';
const nowKR = new Date().toLocaleDateString('ko-KR', { year: 'numeric', month: 'long', day: 'numeric' });

const subject = '[PRESSCO21] 강의 오픈 완료! ' + classTitle + ' 클래스가 공개되었습니다';

const html = '<!DOCTYPE html><html lang="ko"><head><meta charset="UTF-8" /><meta name="viewport" content="width=device-width, initial-scale=1.0" /><title>PRESSCO21 강의 오픈</title></head>'
+ '<body style="margin: 0; padding: 0; background-color: #f8f6f0; font-family: Pretendard, Apple SD Gothic Neo, Malgun Gothic, sans-serif;">'
+ '<table width="100%" cellpadding="0" cellspacing="0" border="0" style="background-color: #f8f6f0;"><tr><td align="center" style="padding: 24px 16px;">'
+ '<table width="600" cellpadding="0" cellspacing="0" border="0" style="max-width: 600px; width: 100%; background-color: #ffffff; border-radius: 8px; overflow: hidden; box-shadow: 0 2px 8px rgba(0,0,0,0.06);">'
+ '<tr><td style="padding: 24px 32px; text-align: center; border-bottom: 2px solid #b89b5e;">'
+ '<span style="font-size: 22px; font-weight: 700; color: #b89b5e; letter-spacing: 2px;">PRESSCO21</span><br />'
+ '<span style="font-size: 11px; color: #999999; letter-spacing: 1px;">Forever and ever and Blooming</span>'
+ '</td></tr>'
+ '<tr><td style="padding: 32px 32px 0; text-align: center;">'
+ '<span style="display: inline-block; background-color: #4a8c5c; color: #ffffff; font-size: 14px; font-weight: 700; padding: 8px 24px; border-radius: 20px; letter-spacing: 1px;">CLASS LIVE</span>'
+ '</td></tr>'
+ '<tr><td style="padding: 28px 32px 32px;">'
+ '<p style="margin: 0 0 24px; font-size: 15px; color: #333333; line-height: 1.7;"><strong style="color: #b89b5e;">' + partnerName + '</strong>님, 축하드립니다!</p>'
+ '<p style="margin: 0 0 8px; font-size: 15px; color: #333333; line-height: 1.7;">검수가 완료되어 <strong>' + classTitle + '</strong> 클래스가<br />PRESSCO21 플랫폼에 공개되었습니다.</p>'
+ '<table width="100%" cellpadding="0" cellspacing="0" border="0" style="background-color: #faf8f3; border-radius: 8px; border: 1px solid #e8e4db; margin: 24px 0;">'
+ '<tr><td style="padding: 20px 24px;">'
+ '<table width="100%"><tr><td style="padding: 8px 0; font-size: 13px; color: #999999; width: 100px;">강의명</td><td style="padding: 8px 0; font-size: 14px; color: #333333; font-weight: 700;">' + classTitle + '</td></tr>'
+ '<tr><td style="padding: 8px 0; font-size: 13px; color: #999999;">수강료</td><td style="padding: 8px 0; font-size: 14px; color: #333333;">' + classPrice + '</td></tr>'
+ '<tr><td style="padding: 8px 0; font-size: 13px; color: #999999;">오픈일</td><td style="padding: 8px 0; font-size: 14px; color: #333333;">' + nowKR + '</td></tr>'
+ '</table></td></tr></table>'
+ '<div style="text-align: center; margin: 28px 0;">'
+ '<a href="' + classUrl + '" style="display: inline-block; background-color: #b89b5e; color: #ffffff; font-size: 15px; font-weight: 700; padding: 14px 32px; border-radius: 6px; text-decoration: none; letter-spacing: 0.5px;">내 클래스 보기</a>'
+ '</div>'
+ '<p style="margin: 0 0 8px; font-size: 14px; color: #555555; line-height: 1.7;">파트너 대시보드에서 예약 현황과 수익을 확인하실 수 있습니다.</p>'
+ '<p style="margin: 0; font-size: 14px; color: #555555; line-height: 1.7;">궁금하신 점은 pressco21@foreverlove.co.kr로 연락주세요.</p>'
+ '</td></tr>'
+ '<tr><td style="padding: 0 32px 32px;"><p style="margin: 0; font-size: 14px; color: #b89b5e; font-weight: 600;">PRESSCO21 드림</p></td></tr>'
+ '<tr><td style="padding: 24px 32px; text-align: center; background-color: #faf8f3; border-top: 1px solid #e8e4db;">'
+ '<p style="margin: 0 0 8px; font-size: 12px; color: #999999;">PRESSCO21 | foreverlove.co.kr</p>'
+ '<p style="margin: 0; font-size: 11px; color: #bbbbbb;">이 메일은 PRESSCO21 파트너 프로그램 관련 안내 메일입니다.</p>'
+ '</td></tr></table></td></tr></table></body></html>';

return [{ json: {
  ...data,
  _email: { to: data._partnerEmail, subject, html },
  _classUrl: classUrl
} }];
